    /// Test that base package exports have correct package attribution in completions.
    #[test]
    fn test_completion_base_package_attribution() {
        use crate::package_library::PackageInfo;
        use crate::state::{Document, WorldState};
        use tower_lsp::lsp_types::{CompletionResponse, Position};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let mut state = WorldState::new();

            // Build a PackageLibrary with base packages set, then wrap in Arc
            let mut pkg_lib = crate::package_library::PackageLibrary::new_empty();
            let mut base_pkgs = std::collections::HashSet::new();
            base_pkgs.insert("base".to_string());
            base_pkgs.insert("utils".to_string());
            pkg_lib.set_base_packages(base_pkgs);
            state.package_library = std::sync::Arc::new(pkg_lib);

            // Insert per-package exports (uses interior mutability, works through Arc)
            let mut base_exports = std::collections::HashSet::new();
            base_exports.insert("source".to_string());
            base_exports.insert("cat".to_string());
            let base_info = PackageInfo::new("base".to_string(), base_exports);
            state.package_library.insert_package(base_info).await;

            let mut utils_exports = std::collections::HashSet::new();
            utils_exports.insert("read.csv".to_string());
            let utils_info = PackageInfo::new("utils".to_string(), utils_exports);
            state.package_library.insert_package(utils_info).await;

            state.package_library_ready = true;

            // Create a document with no library() calls - base exports should still appear
            let code = "x <- ";
            let uri = Url::parse("file:///test.R").unwrap();
            let doc = Document::new(code, None);
            state.documents.insert(uri.clone(), doc);

            let position = Position::new(0, 5);
            let completions = super::completion(&state, &uri, position, None);

            if let Some(CompletionResponse::Array(items)) = completions {
                // "source" should appear with {base} attribution
                let source_item = items
                    .iter()
                    .find(|i| i.label == "source")
                    .expect("Should find 'source' in completions");
                assert_eq!(source_item.detail.as_deref(), Some("{base}"));
                assert!(
                    source_item.data.is_some(),
                    "source should have data for resolve"
                );

                // "read.csv" should appear with {utils} attribution
                let read_csv = items
                    .iter()
                    .find(|i| i.label == "read.csv")
                    .expect("Should find 'read.csv' in completions");
                assert_eq!(read_csv.detail.as_deref(), Some("{utils}"));
                assert!(
                    read_csv.data.is_some(),
                    "read.csv should have data for resolve"
                );
            } else {
                panic!("Expected CompletionResponse::Array");
            }
        });
    }

    // ========================================================================
    // `pkg::` namespace-qualified completion (issue: function completions after
    // a package name). End-to-end through the `completion()` handler.
    // ========================================================================

    /// Seed a one-package library, drop a single-line R document, and run
    /// `completion()` with the cursor at the END of `line` (after any `::`).
    fn namespace_completion_labels(
        line: &str,
        package: &str,
        exports: &[&str],
        packages_enabled: bool,
    ) -> Vec<String> {
        let eol = Position::new(0, line.encode_utf16().count() as u32);
        namespace_completion_labels_at(line, eol, package, exports, packages_enabled)
    }

    #[test]
    fn pkg_double_colon_offers_package_exports() {
        use crate::package_library::{PackageInfo, PackageLibrary};
        use crate::state::{Document, WorldState};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let mut state = WorldState::new();
            state.cross_file_config.packages_enabled = true;
            state.package_library = std::sync::Arc::new(PackageLibrary::new_empty());
            state
                .package_library
                .insert_package(PackageInfo::new(
                    "dplyr".to_string(),
                    std::collections::HashSet::from(["mutate".to_string(), "filter".to_string()]),
                ))
                .await;
            state.package_library_ready = true;

            let uri = Url::parse("file:///test.R").unwrap();
            state
                .documents
                .insert(uri.clone(), Document::new("dplyr::", None));

            let position = Position::new(0, 7);
            let items = match completion(&state, &uri, position, None) {
                Some(CompletionResponse::Array(items)) => items,
                other => panic!("expected array, got {:?}", other),
            };

            let filter = items
                .iter()
                .find(|i| i.label == "filter")
                .expect("dplyr::filter offered");
            assert_eq!(filter.kind, Some(CompletionItemKind::FUNCTION));
            assert_eq!(filter.detail.as_deref(), Some("{dplyr}"));
            assert!(filter.data.is_some(), "carries resolve data for help docs");
            assert!(items.iter().any(|i| i.label == "mutate"));

            // Inside `pkg::`, no general completions leak in.
            assert!(
                !items.iter().any(|i| i.label == "if"),
                "keywords must not appear in a namespace completion list"
            );
        });
    }

    #[test]
    fn pkg_double_colon_backtick_quotes_non_syntactic_export() {
        // End-to-end through `completion()`: a non-syntactic export (operator
        // `%>%`, as real packages declare via `export("%>%")`) must be offered
        // with a backtick-quoted edit so accepting it yields valid R
        // (`magrittr::`%>%``), while the label/filter stay the bare name. A
        // syntactic sibling export inserts its bare name. This guards the
        // handler-seam wiring of `text_edit`/`filter_text`, not just the unit.
        use crate::package_library::{PackageInfo, PackageLibrary};
        use crate::state::{Document, WorldState};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let mut state = WorldState::new();
            state.cross_file_config.packages_enabled = true;
            state.package_library = std::sync::Arc::new(PackageLibrary::new_empty());
            state
                .package_library
                .insert_package(PackageInfo::new(
                    "magrittr".to_string(),
                    std::collections::HashSet::from(["%>%".to_string(), "set_names".to_string()]),
                ))
                .await;
            state.package_library_ready = true;

            let uri = Url::parse("file:///test.R").unwrap();
            state
                .documents
                .insert(uri.clone(), Document::new("magrittr::", None));

            let items = match completion(&state, &uri, Position::new(0, 10), None) {
                Some(CompletionResponse::Array(items)) => items,
                other => panic!("expected array, got {:?}", other),
            };

            // The cursor sits right after `::` (col 10), so the member range is
            // an empty insert there; accepting edits the backtick-quoted text in.
            let empty_at_cursor = Range::new(Position::new(0, 10), Position::new(0, 10));
            let op = items
                .iter()
                .find(|i| i.label == "%>%")
                .expect("magrittr::%>% offered");
            assert_eq!(
                op.text_edit,
                Some(CompletionTextEdit::Edit(TextEdit {
                    range: empty_at_cursor,
                    new_text: "`%>%`".to_string(),
                })),
                "non-syntactic export edits in backtick-quoted text"
            );
            assert_eq!(op.insert_text, None, "edit supersedes insert_text");
            assert_eq!(
                op.filter_text.as_deref(),
                Some("%>%"),
                "filter text stays the bare name so typing `%` still matches"
            );
            // Resolve data still uses the bare topic for the help lookup.
            assert_eq!(
                op.data,
                Some(serde_json::json!({ "topic": "%>%", "package": "magrittr" }))
            );

            let plain = items
                .iter()
                .find(|i| i.label == "set_names")
                .expect("magrittr::set_names offered");
            assert_eq!(
                plain.text_edit,
                Some(CompletionTextEdit::Edit(TextEdit {
                    range: empty_at_cursor,
                    new_text: "set_names".to_string(),
                })),
                "syntactic export edits in its bare name"
            );
            assert_eq!(plain.insert_text, None);
        });
    }

    #[test]
    fn pkg_double_colon_trailing_whitespace_still_offers_exports() {
        // `dplyr:: ` (a space after the operator, no member yet) is valid R.
        // The handler must short-circuit to the package's exports and NOT leak
        // general completions (keywords), honoring the namespace suppression
        // contract even when the cursor sits past trailing whitespace.
        let labels = namespace_completion_labels_at(
            "dplyr:: ",
            Position::new(0, 8),
            "dplyr",
            &["mutate", "filter"],
            true,
        );
        assert!(
            labels.contains(&"mutate".to_string()) && labels.contains(&"filter".to_string()),
            "exports offered after `pkg:: `, got: {labels:?}"
        );
        assert!(
            !labels.contains(&"if".to_string()),
            "keywords must not leak after `pkg:: `, got: {labels:?}"
        );
    }

    #[test]
    fn pkg_double_colon_cursor_on_package_suppresses_completions() {
        // Cursor on the package identifier itself (`dpl|yr::filter`): only
        // package names are valid there, so the popup is suppressed entirely —
        // not the package's members, and not keyword/scope noise (keywords
        // cannot precede `::`).
        let labels = namespace_completion_labels_at(
            "dplyr::filter",
            Position::new(0, 3),
            "dplyr",
            &["mutate", "filter"],
            true,
        );
        assert!(
            labels.is_empty(),
            "package-side cursor must suppress completions, got: {labels:?}"
        );
    }

    #[test]
    fn pkg_triple_colon_offers_nothing() {
        // `:::` (internal access) is detected but deferred — empty list, and
        // crucially NOT a fall-through to keywords.
        let labels = namespace_completion_labels("dplyr:::", "dplyr", &["mutate"], true);
        assert!(labels.is_empty(), "internal access yields no completions");
    }

    #[test]
    fn pkg_double_colon_disabled_falls_through_to_general() {
        // With package awareness off, `::` gets no special handling: the request
        // falls through to general completion (keywords) rather than an empty
        // popup, and the package's members are not offered.
        let labels = namespace_completion_labels("dplyr::", "dplyr", &["mutate"], false);
        assert!(
            labels.contains(&"if".to_string()),
            "disabled `pkg::` falls through to general completion, got: {labels:?}"
        );
        assert!(!labels.contains(&"mutate".to_string()));
    }

    #[test]
    fn pkg_double_colon_resolves_from_disk_before_library_ready() {
        // The namespace path is deliberately NOT gated on `package_library_ready`
        // (unlike the bare-identifier package path): an installed package's
        // exports resolve from its on-disk NAMESPACE during the startup window,
        // before the cache is warmed. A future readiness gate would break this.
        use crate::package_library::PackageLibrary;
        use crate::state::{Document, WorldState};

        let lib_root = tempfile::tempdir().unwrap();
        let pkg_dir = lib_root.path().join("diskpkg");
        std::fs::create_dir_all(&pkg_dir).unwrap();
        std::fs::write(pkg_dir.join("NAMESPACE"), "export(disk_fn)\n").unwrap();

        let mut state = WorldState::new();
        state.cross_file_config.packages_enabled = true;
        let mut lib = PackageLibrary::new_empty();
        lib.set_lib_paths(vec![lib_root.path().to_path_buf()]);
        state.package_library = std::sync::Arc::new(lib);
        // Crucially NOT ready, and the package was never library()-loaded.
        state.package_library_ready = false;

        let uri = Url::parse("file:///test.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new("diskpkg::", None));

        let labels = match completion(&state, &uri, Position::new(0, 9), None) {
            Some(CompletionResponse::Array(items)) => {
                items.into_iter().map(|i| i.label).collect::<Vec<_>>()
            }
            other => panic!("expected array, got {:?}", other),
        };
        assert_eq!(labels, vec!["disk_fn"]);
    }

    /// Variant of [`namespace_completion_labels`] with an explicit cursor
    /// position (for cursor-on-package-side cases).
    fn namespace_completion_labels_at(
        text: &str,
        position: Position,
        package: &str,
        exports: &[&str],
        packages_enabled: bool,
    ) -> Vec<String> {
        use crate::package_library::{PackageInfo, PackageLibrary};
        use crate::state::{Document, WorldState};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let mut state = WorldState::new();
            state.cross_file_config.packages_enabled = packages_enabled;
            state.package_library = std::sync::Arc::new(PackageLibrary::new_empty());
            state
                .package_library
                .insert_package(PackageInfo::new(
                    package.to_string(),
                    exports.iter().map(|s| s.to_string()).collect(),
                ))
                .await;
            state.package_library_ready = true;

            let uri = Url::parse("file:///test.R").unwrap();
            state
                .documents
                .insert(uri.clone(), Document::new(text, None));

            match completion(&state, &uri, position, None) {
                Some(CompletionResponse::Array(items)) => {
                    items.into_iter().map(|i| i.label).collect()
                }
                other => panic!("expected array, got {:?}", other),
            }
        })
    }

    // ========================================================================
    // Package-mode completion: package-internal and NAMESPACE full-imports
    // Regression tests for bugs found by the 2026-05-10 review.
    // ========================================================================

    /// Package-internal symbols (from sibling `R/*.R` files) injected via
    /// `append_package_contribution` must appear in completions.
    ///
    /// Regression: `push_scoped_symbol_completion` previously filtered every
    /// URI starting with `"package:"`, which unintentionally caught the
    /// synthetic `package:///internal` URI used for internal symbols and
    /// excluded the user's OWN package exports from autocomplete.
    #[test]
    fn test_completion_includes_package_internal_symbols() {
        use crate::package_state::PackageScopeContribution;
        use crate::state::{Document, WorldState};
        use std::collections::BTreeSet;
        use tower_lsp::lsp_types::{CompletionResponse, Position};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let workspace_root = Url::parse("file:///work/pkg").unwrap();
            let mut state = WorldState::new();
            state.workspace_folders = vec![workspace_root.clone()];
            state.workspace_scan_complete = true;

            // Seed the package contribution as if `R/utils.R` defined
            // `helper_fn` and the scan has already derived the contribution.
            let mut internal = BTreeSet::new();
            internal.insert("helper_fn".to_string());
            state
                .package_state
                .set_from(crate::package_state::PackageState {
                    scope_contribution: PackageScopeContribution {
                        workspace_root: Some(std::path::PathBuf::from("/work/pkg")),
                        package_name: None,
                        r_internal_symbols: std::sync::Arc::new(internal),
                        imported_symbols: Default::default(),
                        full_imports: Default::default(),
                        test_attached_packages: Default::default(),
                        test_helper_symbols: Default::default(),
                        test_helper_attached_packages: Default::default(),
                        dataset_symbols: Default::default(),
                        sysdata_symbols: Default::default(),
                        onload_symbols: Default::default(),
                            ..PackageScopeContribution::default()
                    },
                    ..Default::default()
                });

            // Open `R/main.R` under the package.
            let uri = Url::parse("file:///work/pkg/R/main.R").unwrap();
            let code = "result <- h";
            let doc = Document::new(code, None);
            state.documents.insert(uri.clone(), doc);

            let completions = super::completion(&state, &uri, Position::new(0, 11), None);
            let items = match completions.expect("completions returned") {
                CompletionResponse::Array(items) => items,
                other => panic!("Expected Array, got {:?}", other),
            };

            assert!(
                items.iter().any(|i| i.label == "helper_fn"),
                "`helper_fn` must appear in completions for a package R/ file when \
                 r_internal_symbols carries it. labels: {:?}",
                items.iter().map(|i| &i.label).collect::<Vec<_>>(),
            );

            let helper = items.iter().find(|i| i.label == "helper_fn").unwrap();
            // The synthetic `package:///internal` URI must not leak into
            // user-visible fields — check detail doesn't say "from internal".
            if let Some(detail) = &helper.detail {
                assert!(
                    !detail.contains("from internal"),
                    "package-internal detail must not expose the synthetic URI path segment; got: {:?}",
                    detail,
                );
            }
        });
    }

    /// NAMESPACE `import(pkg)` (whole-package imports) must contribute
    /// exports to completions, matching how they already contribute to
    /// diagnostic suppression via `scope_contribution.full_imports`.
    ///
    /// Regression: the completion `all_packages` collection chained only
    /// `inherited_packages` and `loaded_packages`, missing `full_imports`.
    #[test]
    fn test_completion_includes_full_imports_packages() {
        use crate::package_library::PackageInfo;
        use crate::package_state::PackageScopeContribution;
        use crate::state::{Document, WorldState};
        use std::collections::{BTreeSet, HashSet};
        use tower_lsp::lsp_types::{CompletionResponse, Position};

        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            let workspace_root = Url::parse("file:///work/pkg").unwrap();
            let mut state = WorldState::new();
            state.workspace_folders = vec![workspace_root.clone()];
            state.workspace_scan_complete = true;
            state.cross_file_config.packages_enabled = true;
            state.package_library_ready = true;

            // Seed `ggplot2` with an export and register it as a full
            // (whole-package) import in `scope_contribution`.
            let mut ggplot_exports = HashSet::new();
            ggplot_exports.insert("ggplot".to_string());
            state
                .package_library
                .insert_package(PackageInfo::new("ggplot2".to_string(), ggplot_exports))
                .await;
            let mut full = BTreeSet::new();
            full.insert("ggplot2".to_string());
            state
                .package_state
                .set_from(crate::package_state::PackageState {
                    scope_contribution: PackageScopeContribution {
                        workspace_root: Some(std::path::PathBuf::from("/work/pkg")),
                        package_name: None,
                        r_internal_symbols: Default::default(),
                        imported_symbols: Default::default(),
                        full_imports: std::sync::Arc::new(full),
                        test_attached_packages: Default::default(),
                        test_helper_symbols: Default::default(),
                        test_helper_attached_packages: Default::default(),
                        dataset_symbols: Default::default(),
                        sysdata_symbols: Default::default(),
                        onload_symbols: Default::default(),
                        ..PackageScopeContribution::default()
                    },
                    ..Default::default()
                });

            let uri = Url::parse("file:///work/pkg/R/plot.R").unwrap();
            let code = "p <- g";
            let doc = Document::new(code, None);
            state.documents.insert(uri.clone(), doc);

            let completions = super::completion(&state, &uri, Position::new(0, 6), None);
            let items = match completions.expect("completions returned") {
                CompletionResponse::Array(items) => items,
                other => panic!("Expected Array, got {:?}", other),
            };

            assert!(
                items.iter().any(|i| i.label == "ggplot"),
                "NAMESPACE `import(ggplot2)` must contribute `ggplot` to completions. \
                 labels: {:?}",
                items.iter().map(|i| &i.label).collect::<Vec<_>>(),
            );
        });
    }

    /// Diagnostic pipeline: a NAMESPACE `importFrom(tidyr, pivot_longer)`
    /// must suppress "pivot_longer is not defined" for an `R/*.R`
    /// file under the package.
    ///
    /// The suppression flows through `parent_symbol_names` — the collector
    /// pre-computes scope at `(0, 0)` via the recursive
    /// `scope_at_position_with_graph_cached` entry point, which DOES receive
    /// `Some(&scope_contribution)` and therefore injects both
    /// `r_internal_symbols` and `imported_symbols`. Names in the resulting
    /// parent set short-circuit the diagnostic loop before it reaches the
    /// `ScopeStream` fast path. This test pins that end-to-end behavior.
    #[tokio::test]
    #[allow(non_snake_case)]
    async fn test_diagnostic_suppresses_importFrom_in_package_file() {
        use crate::package_state::PackageScopeContribution;
        use crate::state::{Document, WorldState};
        use std::collections::{BTreeMap, BTreeSet};

        let workspace_root = Url::parse("file:///work/pkg").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = true;

        // `pivot_longer` is not a base-R builtin, so it's NOT filtered out
        // by `is_builtin` — the suppression must come from the package
        // contribution.
        let mut imported: BTreeMap<String, BTreeSet<String>> = BTreeMap::new();
        let mut pkgs = BTreeSet::new();
        pkgs.insert("tidyr".to_string());
        imported.insert("pivot_longer".to_string(), pkgs);
        state
            .package_state
            .set_from(crate::package_state::PackageState {
                scope_contribution: PackageScopeContribution {
                    workspace_root: Some(std::path::PathBuf::from("/work/pkg")),
                    package_name: None,
                    r_internal_symbols: Default::default(),
                    imported_symbols: std::sync::Arc::new(imported),
                    full_imports: Default::default(),
                    test_attached_packages: Default::default(),
                    test_helper_symbols: Default::default(),
                    test_helper_attached_packages: Default::default(),
                    dataset_symbols: Default::default(),
                    sysdata_symbols: Default::default(),
                    onload_symbols: Default::default(),
                    ..PackageScopeContribution::default()
                },
                ..Default::default()
            });

        let code = "x <- pivot_longer(df)\ny <- totally_undefined_baseline()\n";
        let uri = Url::parse("file:///work/pkg/R/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        // Sanity: the baseline undefined symbol MUST still be flagged —
        // otherwise the collector isn't running and the test is vacuous.
        assert!(
            diagnostics
                .iter()
                .any(|d| d.message == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; pipeline may not be firing. messages: {:?}",
            diagnostics
                .iter()
                .map(|d| d.message.clone())
                .collect::<Vec<_>>(),
        );
        assert!(
            !diagnostics
                .iter()
                .any(|d| d.message == "pivot_longer is not defined"),
            "importFrom(tidyr, pivot_longer) in the package NAMESPACE must suppress \
             `pivot_longer is not defined` for R/ files. messages: {:?}",
            diagnostics
                .iter()
                .map(|d| d.message.clone())
                .collect::<Vec<_>>(),
        );
    }

    /// Workstream B: a NAMESPACE `importFrom(pkg, fn)` MUST suppress
    /// "fn is not defined" for `R/*.R` files even when `pkg` is NOT
    /// installed — the explicit symbol name is statically known from the
    /// NAMESPACE directive and needs no package library lookup.
    ///
    /// This test exercises the FULL derivation path (NAMESPACE text →
    /// `derive_package_state` → `scope_contribution.imported_symbols` →
    /// scope injection → diagnostic suppression), unlike
    /// `test_diagnostic_suppresses_importFrom_in_package_file` which uses
    /// manual `set_from`.
    #[tokio::test]
    async fn test_importfrom_resolves_without_source_package_installed() {
        use crate::package_state::{
            ContentDigest, DescriptionInput, NamespaceInput, PackageInputDelta, RFileInput,
            RFileKind,
        };
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work/pkg").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        // package_library_ready is FALSE — simulates R unavailable / source
        // package not installed (CI environment with no R).
        state.package_library_ready = false;

        // Set up package inputs with NAMESPACE containing importFrom for a
        // non-installed package.
        state.package_inputs.workspace_root = Some(std::path::PathBuf::from("/work/pkg"));
        state.package_inputs.package_mode = crate::cross_file::config::PackageMode::Auto;
        state.package_inputs.description = Some(DescriptionInput {
            text: "Package: mypkg\nImports: nonexistent_pkg_xyz\n".into(),
        });
        state.package_inputs.namespace = Some(NamespaceInput {
            text:
                "importFrom(nonexistent_pkg_xyz, imported_fn, another_imported)\nexport(my_func)\n"
                    .into(),
        });
        let r_text: std::sync::Arc<str> =
            "my_func <- function() {\n  imported_fn()\n  another_imported()\n  genuine_undefined()\n}\n"
                .into();
        state.package_inputs.r_files.insert(
            std::path::PathBuf::from("/work/pkg/R/main.R"),
            RFileInput {
                kind: RFileKind::Source,
                text: r_text.clone(),
                content_digest: ContentDigest::of(&r_text),
            },
        );
        state.apply_package_event(&PackageInputDelta::Initial);

        // Verify derivation produced the imported symbols.
        assert!(
            state
                .package_state
                .scope_contribution()
                .imported_symbols
                .contains_key("imported_fn"),
            "derivation must populate imported_symbols from NAMESPACE importFrom: {:?}",
            state.package_state.scope_contribution().imported_symbols,
        );

        let code = "my_func <- function() {\n  imported_fn()\n  another_imported()\n  genuine_undefined()\n}\n";
        let uri = Url::parse("file:///work/pkg/R/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        let messages: Vec<_> = diagnostics.iter().map(|d| d.message.as_str()).collect();
        assert!(
            messages.contains(&"genuine_undefined is not defined"),
            "baseline undefined MUST still fire; got: {messages:?}",
        );
        assert!(
            !messages.iter().any(|m| m.contains("imported_fn")),
            "importFrom symbol must not be flagged even when source package is absent; got: {messages:?}",
        );
        assert!(
            !messages.iter().any(|m| m.contains("another_imported")),
            "all importFrom symbols must resolve; got: {messages:?}",
        );
    }

    /// Workstream B negative test: `import(pkg)` (whole-package import) does
    /// NOT make arbitrary symbols resolve when the package is not installed.
    /// Only explicitly NAMED `importFrom(pkg, fn)` symbols are trusted
    /// without install; whole-package imports legitimately need the package's
    /// export list to know what's available.
    #[tokio::test]
    async fn test_whole_package_import_does_not_resolve_arbitrary_symbols_when_uninstalled() {
        use crate::package_state::{
            ContentDigest, DescriptionInput, NamespaceInput, PackageInputDelta, RFileInput,
            RFileKind,
        };
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work/pkg").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = false;

        state.package_inputs.workspace_root = Some(std::path::PathBuf::from("/work/pkg"));
        state.package_inputs.package_mode = crate::cross_file::config::PackageMode::Auto;
        state.package_inputs.description = Some(DescriptionInput {
            text: "Package: mypkg\nImports: nonexistent_pkg_xyz\n".into(),
        });
        // Only whole-package import — no importFrom for specific symbols.
        state.package_inputs.namespace = Some(NamespaceInput {
            text: "import(nonexistent_pkg_xyz)\nexport(my_func)\n".into(),
        });
        let r_text: std::sync::Arc<str> =
            "my_func <- function() {\n  some_function_from_pkg()\n}\n".into();
        state.package_inputs.r_files.insert(
            std::path::PathBuf::from("/work/pkg/R/main.R"),
            RFileInput {
                kind: RFileKind::Source,
                text: r_text.clone(),
                content_digest: ContentDigest::of(&r_text),
            },
        );
        state.apply_package_event(&PackageInputDelta::Initial);

        // `imported_symbols` must be empty — only importFrom populates it.
        assert!(
            state
                .package_state
                .scope_contribution()
                .imported_symbols
                .is_empty(),
            "whole-package import must NOT populate imported_symbols: {:?}",
            state.package_state.scope_contribution().imported_symbols,
        );
        // `full_imports` must contain the package name.
        assert!(
            state
                .package_state
                .scope_contribution()
                .full_imports
                .contains("nonexistent_pkg_xyz"),
            "import(pkg) must appear in full_imports: {:?}",
            state.package_state.scope_contribution().full_imports,
        );

        let code = "my_func <- function() {\n  some_function_from_pkg()\n}\n";
        let uri = Url::parse("file:///work/pkg/R/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        // When the package is NOT installed and library is NOT ready, the
        // symbol cannot be resolved via the package library. The undefined-
        // variable diagnostic SHOULD fire (the pending-cache suppression
        // only kicks in when `package_library_ready` is true and the
        // package exists on disk).
        let messages: Vec<_> = diagnostics.iter().map(|d| d.message.as_str()).collect();
        assert!(
            messages
                .iter()
                .any(|m| m.contains("some_function_from_pkg")),
            "whole-package import with uninstalled package must NOT resolve arbitrary symbols; got: {messages:?}",
        );
    }

