    /// Issue #398 end-to-end: data.table visibility derived from package
    /// metadata — modeled via `full_imports` (NAMESPACE `import(data.table)` /
    /// DESCRIPTION `Imports: data.table`), NOT a directly-injected package
    /// list — must flow through `collect_in_play_packages`, put data.table in
    /// play, and so suppress the column-name indices of an unresolved-object
    /// `[` for an `R/*.R` file under the package. `dt` is a bound parameter so
    /// it isn't itself flagged; the baseline undefined symbol is the positive
    /// control. The `nse_phase3_*` collector tests only exercise this via
    /// `collect_with_packages(&["data.table"])` (direct injection).
    #[tokio::test]
    async fn nse_data_table_namespace_import_suppresses_index_in_package_file() {
        use crate::package_state::PackageScopeContribution;
        use crate::state::{Document, WorldState};
        use std::collections::BTreeSet;

        let workspace_root = Url::parse("file:///work/pkg").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = true;

        // Model `import(data.table)` / `Imports: data.table` via full_imports.
        let mut full_imports = BTreeSet::new();
        full_imports.insert("data.table".to_string());
        state
            .package_state
            .set_from(crate::package_state::PackageState {
                scope_contribution: PackageScopeContribution {
                    workspace_root: Some(std::path::PathBuf::from("/work/pkg")),
                    package_name: None,
                    r_internal_symbols: Default::default(),
                    imported_symbols: Default::default(),
                    full_imports: std::sync::Arc::new(full_imports),
                    test_attached_packages: Default::default(),
                    test_helper_symbols: Default::default(),
                    test_helper_attached_packages: Default::default(),
                    dataset_symbols: Default::default(),
                    sysdata_symbols: Default::default(),
                    onload_symbols: Default::default(),
                    ..PackageScopeContribution::default()
                },
                ..Default::default()
            });

        let code = "f <- function(dt) dt[, value, by = grp]\ny <- totally_undefined_baseline()\n";
        let uri = Url::parse("file:///work/pkg/R/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();

        // Baseline proves the collector ran (otherwise the test is vacuous).
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; pipeline may not be firing. \
             messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("value") || m.contains("grp")),
            "import(data.table) must put data.table in play and suppress the \
             column-name indices `value`/`grp`; messages: {messages:?}"
        );
    }

    /// Issue #398 end-to-end: a resolved export of a loaded package that has no
    /// NSE policy is standard-eval, so its argument IS checked. The `nse_phase*`
    /// collector tests cannot reach this branch — they build `NseAnalysis` with
    /// `package_library = None` — so this is the only test that pins
    /// `resolve_call_arg_policy` step 4 (the `is_symbol_from_loaded_packages`
    /// path). The contrast call pins the boundary: an *unresolved* callee falls
    /// back to `WholeCall` and suppresses its argument. A synthetic package
    /// keeps the test immune to future base-export / policy-table additions.
    #[tokio::test]
    async fn nse_resolved_package_export_without_policy_checks_arg_end_to_end() {
        use crate::package_library::PackageInfo;
        use crate::state::{Document, WorldState};

        let mut state = WorldState::new();
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = true;

        let mut exports = std::collections::HashSet::new();
        exports.insert("my_fn".to_string());
        state
            .package_library
            .insert_package(PackageInfo::new("mypkg".to_string(), exports))
            .await;

        let code = "library(mypkg)\nmy_fn(undefined_var)\nunknown_unresolved_fn(other_var)\n";
        let uri = Url::parse("file:///test.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();

        // Resolved export, no policy -> standard-eval -> argument checked.
        // Use `contains` rather than `==` because the message may have a
        // trailing NSE-hint suffix (the callee `my_fn` is not a builtin or
        // base export, so the hint fires — that is correct behavior per #455).
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_var is not defined")),
            "argument of a resolved no-policy export must be checked; messages: {messages:?}"
        );
        // The resolved export itself must not be flagged. Use
        // `contains("my_fn is not defined")` rather than `contains("my_fn")`
        // because the NSE hint for `undefined_var`'s diagnostic legitimately
        // mentions `my_fn` as the callee (correct behavior per #455).
        assert!(
            !messages.iter().any(|m| m.contains("my_fn is not defined")),
            "resolved package export `my_fn` must not be flagged; messages: {messages:?}"
        );
        // Contrast: an unresolved callee falls back to WholeCall, suppressing
        // its argument...
        assert!(
            !messages.iter().any(|m| m.contains("other_var")),
            "argument of an unresolved callee must be suppressed (WholeCall \
             fallback); messages: {messages:?}"
        );
        // ...while the unresolved callee itself is flagged (proves the contrast
        // is live, not silently empty).
        assert!(
            messages
                .iter()
                .any(|m| m == "unknown_unresolved_fn is not defined"),
            "unresolved callee must be flagged; messages: {messages:?}"
        );
    }

    /// Issue: plyr's `.()` quoting helper. With plyr loaded, `ddply` resolves
    /// to its base per-formal policy (issue #467) — behaviorally standard-eval
    /// at this call site, since `.fun` is `function(x) x` (not a data-masking
    /// verb, so the `...` are not suppressed) — and descends into its
    /// arguments; the nested `.(iso, yearY)` call must suppress the quoted
    /// column names. Before `package_policy("plyr", ".")` existed, `.` resolved
    /// as a no-policy export and was treated as standard-eval, so `iso`/`yearY`
    /// were flagged as undefined (false positives). A synthetic package keeps
    /// the test immune to package-database contents.
    ///
    /// The data-frame argument is itself an *undefined* symbol whose flag is
    /// asserted: this pins the scoping boundary. `ddply`'s base policy captures
    /// nothing here, so it must still descend into and check its non-`.()`
    /// arguments — only the nested `.()` call suppresses. A regression that
    /// wrongly gave `ddply` a `WholeCall` policy (over-suppressing every
    /// argument) would hide this flag and fail the test.
    #[tokio::test]
    async fn nse_plyr_dot_quotes_columns_in_ddply_end_to_end() {
        use crate::package_library::PackageInfo;
        use crate::state::{Document, WorldState};

        let mut state = WorldState::new();
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = true;

        let mut exports = std::collections::HashSet::new();
        exports.insert(".".to_string());
        exports.insert("ddply".to_string());
        state
            .package_library
            .insert_package(PackageInfo::new("plyr".to_string(), exports))
            .await;

        let code = "library(plyr)\n\
                    abortions <- ddply(undefined_df_arg, .(iso, yearY), function(x) x)\n\
                    totally_undefined_baseline\n";
        let uri = Url::parse("file:///test.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();

        // Baseline proves the collector ran (otherwise the test is vacuous).
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; messages: {messages:?}"
        );
        // The columns quoted by `.()` must NOT be flagged.
        assert!(
            !messages.iter().any(|m| m.contains("iso is not defined")),
            "`.(iso, ...)` must suppress the quoted column `iso`; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("yearY is not defined")),
            "`.(.., yearY)` must suppress the quoted column `yearY`; messages: {messages:?}"
        );
        // Scoping boundary: `ddply`'s base policy still checks its data-frame
        // argument, so the undefined `undefined_df_arg` IS flagged. This fails
        // if `ddply` were wrongly given a WholeCall policy.
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_df_arg is not defined")),
            "`ddply`'s data argument must stay checked (standard-eval); messages: {messages:?}"
        );
    }

    /// Collect undefined-variable diagnostic messages for `code` against a
    /// synthetic `plyr` package exporting `exports`, mirroring the harness of
    /// `nse_plyr_dot_quotes_columns_in_ddply_end_to_end`. Shared by the issue
    /// #467 `*ply` data-mask tests below; a synthetic package keeps them immune
    /// to package-database contents.
    #[cfg(test)]
    async fn plyr_undefined_messages(code: &str, exports: &[&str]) -> Vec<String> {
        use crate::package_library::PackageInfo;
        use crate::state::{Document, WorldState};

        let mut state = WorldState::new();
        state.workspace_scan_complete = true;
        state.cross_file_config.packages_enabled = true;
        state.package_library_ready = true;

        let export_set: std::collections::HashSet<String> =
            exports.iter().map(|e| (*e).to_string()).collect();
        state
            .package_library
            .insert_package(PackageInfo::new("plyr".to_string(), export_set))
            .await;

        let uri = Url::parse("file:///test.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );
        diagnostics.iter().map(|d| d.message.clone()).collect()
    }

    /// Issue #467: in `ddply(df, .(year), summarise, n = length(unique(team)))`
    /// plyr forwards the `...` to `summarise`, which evaluates them in each
    /// slice's data mask — so `team` is a column, not a free variable. Because
    /// `summarise` resolves to a dots-capturing (data-masking) policy, the
    /// `*ply` `...` are suppressed. The `.data` argument stays checked (the
    /// scoping boundary), and `.(year)`'s column is suppressed by `.()` (#466).
    #[tokio::test]
    async fn nse_plyr_ddply_summarise_forwards_data_masked_dots_end_to_end() {
        let code = "library(plyr)\n\
                    out <- ddply(undefined_df_arg, .(year), summarise, n = length(unique(team)))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "summarise"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("team is not defined")),
            "`summarise` data-masks the forwarded `...`, so `team` must not be flagged; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("year is not defined")),
            "`.(year)` must suppress the quoted column `year`; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_df_arg is not defined")),
            "`ddply`'s `.data` argument must stay checked; messages: {messages:?}"
        );
    }

    /// Issue #467, the complementary shape: with an ordinary `.fun` (`nrow`, not
    /// a data-masking verb) the forwarded `...` are NOT data-masked, so a
    /// genuine typo among them must still be flagged. A blanket `...`
    /// suppression on `ddply` would wrongly hide this.
    #[tokio::test]
    async fn nse_plyr_ddply_ordinary_fun_keeps_dots_checked_end_to_end() {
        let code = "library(plyr)\n\
                    ddply(some_df, .(year), nrow, extra = undefined_typo)\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_typo is not defined")),
            "an ordinary `.fun` leaves the forwarded `...` checked, so the typo must be flagged; messages: {messages:?}"
        );
    }

    /// Issue #467: `transform` is base R's data-masking verb — it resolves via
    /// `base_policy` (not the plyr table), exercising the policy-driven `.fun`
    /// detection through a different resolution path than `plyr::summarise`.
    #[tokio::test]
    async fn nse_plyr_ddply_transform_forwards_data_masked_dots_end_to_end() {
        let code = "library(plyr)\n\
                    ddply(some_df, .(year), transform, doubled = raw_col * 2)\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("raw_col is not defined")),
            "`transform` data-masks the forwarded `...`, so `raw_col` must not be flagged; messages: {messages:?}"
        );
    }

    /// Issue #467: `llply(.data, .fun, ...)` puts `.fun` at the 2nd position
    /// (vs `ddply`'s 3rd) — pins that the forwarded-dots upgrade locates `.fun`
    /// by each verb's own formal order, not a fixed position.
    #[tokio::test]
    async fn nse_plyr_llply_summarise_locates_fun_at_second_position_end_to_end() {
        let code = "library(plyr)\n\
                    llply(undefined_input, summarise, total = sum(value_col))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &["llply", "summarise"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("value_col is not defined")),
            "`summarise` as `llply`'s 2nd-position `.fun` must data-mask the `...`; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_input is not defined")),
            "`llply`'s `.data` must stay checked; messages: {messages:?}"
        );
    }

    /// Issue #467: a locally-defined `summarise` shadows the plyr verb, so plyr
    /// would call the local function (which does not data-mask). The forwarded
    /// `...` must stay checked, so a typo is still flagged — the upgrade honors
    /// local shadowing rather than blindly trusting the bare `.fun` name.
    #[tokio::test]
    async fn nse_plyr_ddply_locally_shadowed_fun_keeps_dots_checked_end_to_end() {
        let code = "library(plyr)\n\
                    summarise <- function(x) nrow(x)\n\
                    ddply(some_df, .(year), summarise, undefined_typo)\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_typo is not defined")),
            "a locally-shadowed `.fun` does not data-mask, so the typo must be flagged; messages: {messages:?}"
        );
    }

    /// Issue #467: a pipe supplies `.data` implicitly, shifting `.fun` one
    /// position left. `some_df %>% ddply(.(g), summarise, n = mean(value_col))`
    /// must still locate `.fun` (via the threaded `pipe_fed`) and data-mask the
    /// forwarded `...`.
    #[tokio::test]
    async fn nse_plyr_ddply_pipe_fed_locates_fun_end_to_end() {
        let code = "library(plyr)\n\
                    some_df %>% ddply(.(g), summarise, n = mean(value_col))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "summarise", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("value_col is not defined")),
            "a piped `.fun` (summarise) must still data-mask the forwarded `...`; messages: {messages:?}"
        );
    }

    /// Issue #467: a namespace-qualified data-masking `.fun` (`plyr::summarise`)
    /// resolves through the qualified arm of `fun_resolves_to_data_masking_verb`
    /// and still suppresses the forwarded `...`.
    #[tokio::test]
    async fn nse_plyr_ddply_qualified_fun_forwards_data_masked_dots_end_to_end() {
        let code = "library(plyr)\n\
                    ddply(some_df, .(year), plyr::summarise, n = length(unique(team)))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("team is not defined")),
            "`plyr::summarise` as `.fun` must data-mask the forwarded `...`; messages: {messages:?}"
        );
    }

    /// Issue #467: the post-`...` control formals in `plyr_split_apply_formals`
    /// are load-bearing. Even when `.fun` is data-masking (so `captured_dots`
    /// is upgraded to true), a NAMED control argument such as `.drop = bad_typo`
    /// matches its enumerated formal and stays CHECKED — it is not absorbed by
    /// `...`. Dropping the control formals from the list would silently suppress
    /// it, hiding a real undefined-variable bug. (A bare identifier is a
    /// contrived `.drop` value, but a logical literal would not surface a
    /// diagnostic; the point is to exercise the formal-vs-dots mask.) The
    /// genuinely data-masked `n = mean(value_col)` stays suppressed, proving the
    /// upgrade did fire — so this isolates the control-formal exemption.
    #[tokio::test]
    async fn nse_plyr_ddply_named_control_formal_stays_checked_end_to_end() {
        let code = "library(plyr)\n\
                    ddply(some_df, .(g), summarise, .drop = bad_typo, n = mean(value_col))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "summarise", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("bad_typo is not defined")),
            "a named control formal (`.drop`) stays checked even when `.fun` data-masks; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("value_col is not defined")),
            "the genuinely data-masked `...` column must still be suppressed (proves the upgrade fired); messages: {messages:?}"
        );
    }

    /// Issue #467: `.fun` supplied BY NAME (`.fun = summarise`) is located via
    /// the named-matching pass of `per_formal_mask` and its value extracted from
    /// a named-argument node — a distinct path from the positional `.fun` the
    /// other tests exercise.
    #[tokio::test]
    async fn nse_plyr_ddply_named_fun_argument_end_to_end() {
        let code = "library(plyr)\n\
                    ddply(some_df, .variables = .(g), .fun = summarise, n = mean(value_col))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "summarise", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("value_col is not defined")),
            "a named `.fun = summarise` must still be located and data-mask the `...`; messages: {messages:?}"
        );
    }

    /// Issue #467 follow-up (Codex review): the `m*ply` family wraps `.fun` in
    /// `splat()` — `mdply(.data, .fun, ...)` calls `do.call(splat(.fun),
    /// c(row_values, list(...)))`, so the m*ply call's `...` are spread as
    /// ORDINARY arguments, never forwarded into `.fun`'s per-group data mask.
    /// Verified against plyr 1.8.9: `mdply(df, summarise, z = sum(x))` errors
    /// with "object 'x' not found" because `x` is not a visible column. So the
    /// `m*ply` verbs must NOT get the data-mask upgrade — their `...` stay
    /// checked even with a data-masking `.fun`, so a typo is still flagged.
    #[tokio::test]
    async fn nse_plyr_mdply_splat_fun_keeps_dots_checked_end_to_end() {
        let code = "library(plyr)\n\
                    mdply(some_df, summarise, n = undefined_typo)\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &["mdply", "summarise", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            messages
                .iter()
                .any(|m| m.contains("undefined_typo is not defined")),
            "`mdply` splats `.fun`, so its `...` are NOT data-masked and the typo must be flagged; messages: {messages:?}"
        );
    }

    /// Issue #467 follow-up (Codex review): a local qualified alias of a `*ply`
    /// verb (`my_ddply <- plyr::ddply`) resolves through the alias path of
    /// `resolve_call_arg_policy`, which must apply the same `.fun`-conditional
    /// dots upgrade — otherwise `my_ddply(df, .(g), summarise, …)` would keep a
    /// data-masked column checked while the identical direct `ddply(...)` call
    /// suppresses it.
    #[tokio::test]
    async fn nse_plyr_qualified_alias_applies_dots_upgrade_end_to_end() {
        let code = "library(plyr)\n\
                    my_ddply <- plyr::ddply\n\
                    my_ddply(some_df, .(year), summarise, n = length(unique(team)))\n\
                    totally_undefined_baseline\n";
        let messages = plyr_undefined_messages(code, &[".", "ddply", "summarise", "some_df"]).await;
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("team is not defined")),
            "an aliased `*ply` (`my_ddply <- plyr::ddply`) must apply the data-mask upgrade; messages: {messages:?}"
        );
    }

    /// Regression: tree-sitter-r parses `return` as a plain identifier (not a
    /// keyword node), so `return(x)` is an ordinary `call`. The
    /// undefined-variable collector must not flag `return`, because it is a
    /// registered builtin (`is_builtin("return")`) — note `return` is NOT in
    /// the `reserved_words` list, so the builtin guard is what suppresses it.
    #[tokio::test]
    async fn test_diagnostic_does_not_flag_return_call() {
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;

        let code = "f <- function(x) { return(x) }\ng <- totally_undefined_baseline()\n";
        let uri = Url::parse("file:///work/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));
        let tree = {
            let mut parser = tree_sitter::Parser::new();
            parser
                .set_language(&tree_sitter_r::LANGUAGE.into())
                .unwrap();
            parser.parse(code, None).unwrap()
        };

        let mut diagnostics = Vec::new();
        let snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &snapshot,
            &uri,
            tree.root_node(),
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        // Sanity: the baseline undefined symbol MUST be flagged — otherwise the
        // collector isn't running and the test is vacuous.
        assert!(
            diagnostics
                .iter()
                .any(|d| d.message == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; pipeline may not be firing. messages: {:?}",
            diagnostics
                .iter()
                .map(|d| d.message.clone())
                .collect::<Vec<_>>(),
        );
        assert!(
            !diagnostics
                .iter()
                .any(|d| d.message == "return is not defined"),
            "`return(...)` must not be flagged as undefined (return is a builtin). messages: {:?}",
            diagnostics
                .iter()
                .map(|d| d.message.clone())
                .collect::<Vec<_>>(),
        );
    }

    /// A nested closure can refer to a binding installed later in its enclosing
    /// function before the closure is called. R resolves that name at call time
    /// through the enclosing function environment, so this is not a true
    /// forward-reference error.
    #[test]
    fn test_diagnostic_suppresses_later_enclosing_function_binding_in_nested_closure() {
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.undefined_variable_severity = Some(DiagnosticSeverity::WARNING);

        let code = "outer <- function() {\n  inner <- function() later()\n  later <- function() 1\n  inner()\n}\ny <- totally_undefined_baseline()\n";
        let uri = Url::parse("file:///work/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));

        let diagnostics = diagnostics(&state, &uri, &DiagCancelToken::never());
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline undefined symbol must be flagged; messages: {messages:?}"
        );
        assert!(
            !messages.iter().any(|m| m.contains("later")),
            "nested closure should late-bind later enclosing function binding; messages: {messages:?}"
        );
    }

    /// The nested-closure late-binding carve-out must not hide a direct use
    /// before definition in the same function body: `later()` runs before
    /// `later <- ...` installs the binding.
    #[test]
    fn test_diagnostic_flags_same_function_use_before_later_binding() {
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.undefined_variable_severity = Some(DiagnosticSeverity::WARNING);

        let code = "outer <- function() {\n  later()\n  later <- function() 1\n}\n";
        let uri = Url::parse("file:///work/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));

        let diagnostics = diagnostics(&state, &uri, &DiagCancelToken::never());
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();
        assert!(
            messages.iter().any(|m| m == "later is not defined"),
            "direct same-function use before binding must remain diagnostic; messages: {messages:?}"
        );
    }

    /// Assignments inside a top-level if/else/for/while/repeat block are
    /// top-level bindings visible from that statement onward. This is the
    /// pattern used by rlang vendored standalone files:
    /// `if (!exists("is_true")) is_true <- function(x) x`
    /// followed by `is_true(something)`.
    #[test]
    fn test_diagnostic_suppresses_conditional_def_after_if_block() {
        use crate::state::{Document, WorldState};

        let workspace_root = Url::parse("file:///work").unwrap();
        let mut state = WorldState::new();
        state.workspace_folders = vec![workspace_root.clone()];
        state.workspace_scan_complete = true;
        state.cross_file_config.undefined_variable_severity = Some(DiagnosticSeverity::WARNING);

        let code = "if (!exists(\"is_true\")) {\n  is_true <- function(x) x\n}\nis_true(y)\nna_chr <- NA_character_\nif (TRUE) {\n  deferred_run <- function(fn) fn()\n}\ndeferred_run(identity)\ny <- totally_undefined_baseline()\n";
        let uri = Url::parse("file:///work/main.R").unwrap();
        state
            .documents
            .insert(uri.clone(), Document::new(code, None));

        let diagnostics = diagnostics(&state, &uri, &DiagCancelToken::never());
        let messages: Vec<String> = diagnostics.iter().map(|d| d.message.clone()).collect();
        assert!(
            messages
                .iter()
                .any(|m| m == "totally_undefined_baseline is not defined"),
            "baseline undefined must fire; messages: {messages:?}"
        );
        // Use `contains("is_true is not defined")` rather than
        // `contains("is_true")` because `# raven: nse` hint messages for
        // other diagnostics may legitimately mention `is_true` as the callee.
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("is_true is not defined")),
            "conditional def inside if block must not be flagged; messages: {messages:?}"
        );
        assert!(
            !messages
                .iter()
                .any(|m| m.contains("deferred_run is not defined")),
            "conditional def inside if block must not be flagged; messages: {messages:?}"
        );
    }

