    #[test]
    fn test_build_complex_hierarchy() {
        // Complex hierarchy: section -> function -> nested function -> variable
        let symbols = vec![
            RawSymbol {
                name: "Section".to_string(),
                kind: DocumentSymbolKind::Module,
                range: Range {
                    start: Position {
                        line: 0,
                        character: 0,
                    },
                    end: Position {
                        line: 0,
                        character: 15,
                    },
                },
                selection_range: Range {
                    start: Position {
                        line: 0,
                        character: 0,
                    },
                    end: Position {
                        line: 0,
                        character: 15,
                    },
                },
                detail: None,
                section_level: Some(1),
                children: Vec::new(),
            },
            RawSymbol {
                name: "outer".to_string(),
                kind: DocumentSymbolKind::Function,
                range: Range {
                    start: Position {
                        line: 2,
                        character: 0,
                    },
                    end: Position {
                        line: 10,
                        character: 1,
                    },
                },
                selection_range: Range {
                    start: Position {
                        line: 2,
                        character: 0,
                    },
                    end: Position {
                        line: 2,
                        character: 5,
                    },
                },
                detail: Some("()".to_string()),
                section_level: None,
                children: Vec::new(),
            },
            RawSymbol {
                name: "inner".to_string(),
                kind: DocumentSymbolKind::Function,
                range: Range {
                    start: Position {
                        line: 4,
                        character: 4,
                    },
                    end: Position {
                        line: 8,
                        character: 5,
                    },
                },
                selection_range: Range {
                    start: Position {
                        line: 4,
                        character: 4,
                    },
                    end: Position {
                        line: 4,
                        character: 9,
                    },
                },
                detail: Some("(x)".to_string()),
                section_level: None,
                children: Vec::new(),
            },
            RawSymbol {
                name: "deep_var".to_string(),
                kind: DocumentSymbolKind::Variable,
                range: Range {
                    start: Position {
                        line: 6,
                        character: 8,
                    },
                    end: Position {
                        line: 6,
                        character: 20,
                    },
                },
                selection_range: Range {
                    start: Position {
                        line: 6,
                        character: 8,
                    },
                    end: Position {
                        line: 6,
                        character: 16,
                    },
                },
                detail: None,
                section_level: None,
                children: Vec::new(),
            },
        ];

        let builder = HierarchyBuilder::new(symbols, 15);
        let result = builder.build();

        // Section at root
        assert_eq!(result.len(), 1);
        assert_eq!(result[0].name, "Section");

        // outer inside section
        let section_children = result[0].children.as_ref().unwrap();
        assert_eq!(section_children.len(), 1);
        assert_eq!(section_children[0].name, "outer");

        // inner inside outer
        let outer_children = section_children[0].children.as_ref().unwrap();
        assert_eq!(outer_children.len(), 1);
        assert_eq!(outer_children[0].name, "inner");

        // deep_var inside inner
        let inner_children = outer_children[0].children.as_ref().unwrap();
        assert_eq!(inner_children.len(), 1);
        assert_eq!(inner_children[0].name, "deep_var");
    }

