    #[test]
    fn foreach_composition_iterators_do_not_leak() {
        let names = foreach_compose_undefined_names(
            "foreach(i = 1:3) %:% foreach(j = 1:3) %do% i + j\nprint(i)\nprint(j)",
        );
        // After the composed expression neither iterator has an outer binding.
        assert!(names.contains(&"i".to_string()), "got: {names:?}");
        assert!(names.contains(&"j".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_composition_inner_iterator_value_sees_outer_iterator() {
        // The realistic cross-reference idiom: an inner loop's range depends on
        // the outer iterator. `i` inside `foreach(j = seq_len(i))` must resolve
        // to the outer iterator, not be flagged undefined. The outer foreach's
        // scope runs from the end of its call through the body, so it covers the
        // inner call's value expression.
        let names = foreach_compose_undefined_names(
            "foreach(i = 1:3) %:% foreach(j = seq_len(i)) %do% i + j",
        );
        assert!(!names.contains(&"i".to_string()), "got: {names:?}");
        assert!(!names.contains(&"j".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_composition_iterator_value_expression_still_checked() {
        // The composition scope now spans the iterator-value expressions, but a
        // genuinely-undefined symbol there (not an iterator) must still be
        // flagged — the #404 guarantee, carried over to compositions.
        let names = foreach_compose_undefined_names(
            "foreach(i = missing_vec) %:% foreach(j = 1:3) %do% i + j",
        );
        assert!(names.contains(&"missing_vec".to_string()), "got: {names:?}");
        assert!(!names.contains(&"i".to_string()), "got: {names:?}");
        assert!(!names.contains(&"j".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_composition_value_expression_assignment_does_not_leak() {
        // Issue #406 leak behavior: an assignment inside an iterator value
        // expression is evaluated in foreach's own environment, so it never
        // leaks past the composed expression. Verified against real R:
        // `foreach(i = { x <- 1; 1:1 }) %:% foreach(j = 1:1) %do% { i + j }`
        // leaves `exists("x") == FALSE`. The trailing `print(x)` must be flagged.
        let names = foreach_compose_undefined_names(
            "foreach(i = { x <- 1\n1:3 }) %:% foreach(j = 1:3) %do% i + j\nprint(x)",
        );
        assert!(names.contains(&"x".to_string()), "got: {names:?}");
        assert!(!names.contains(&"i".to_string()), "got: {names:?}");
        assert!(!names.contains(&"j".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_value_expression_assignment_not_visible_in_body() {
        // The same isolation also holds toward the body: foreach evaluates the
        // iterator arguments in its own environment, so the body cannot see a
        // value-expression assignment. Verified against real R:
        // `foreach(i = { x <- 1; 1:1 }) %do% { x }` errors with
        // "object 'x' not found". The body reference must be flagged.
        let names = foreach_undefined_names("foreach(i = { x <- 1\n1:3 }) %do% x");
        assert!(names.contains(&"x".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_composition_inner_iterator_shadows_outer() {
        // Same-named iterators across composition levels. The body `i` binds to
        // the inner foreach; after the composed expression `i` does not leak, so
        // `print(i)` is flagged. The outer binding `outer_val`, referenced in the
        // first foreach's value expression, stays visible and is not flagged.
        let names = foreach_compose_undefined_names(
            "outer_val <- 1\nforeach(i = outer_val) %:% foreach(i = 4:6) %do% i\nprint(i)",
        );
        assert!(names.contains(&"i".to_string()), "got: {names:?}");
        assert!(!names.contains(&"outer_val".to_string()), "got: {names:?}");
    }

    #[test]
    fn foreach_composition_body_local_definition_does_not_leak() {
        // A definition made in the composed loop body is scope-local, exactly as
        // in the simple `%do%` case (parallels `foreach_rhs_local_definition_*`).
        let names = foreach_compose_undefined_names(
            "foreach(i = 1:3) %:% foreach(j = 1:3) %do% {\n  inner <- i + j\n  inner\n}\nprint(inner)",
        );
        assert!(names.contains(&"inner".to_string()), "got: {names:?}");
    }

    #[test]
    fn test_function_parameters_not_flagged_as_undefined() {
        let mut state = create_test_state();
        let code = r#"
add <- function(a, b) {
  result <- a + b
  return(result)
}
"#;
        let uri = add_document(&mut state, "file:///test.R", code);
        let tree = parse_r_code(code);
        let root = tree.root_node();

        let mut diagnostics = Vec::new();
        let __snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &__snapshot,
            &uri,
            root,
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        // Filter to only undefined variable warnings (use starts_with for filtering, exact match for assertions)
        let undefined_var_diags: Vec<_> = diagnostics
            .iter()
            .filter(|d| {
                crate::diagnostic_code::diagnostic_has_code(
                    &d.code,
                    crate::diagnostic_code::UNDEFINED_VARIABLE,
                )
            })
            .collect();

        // Print diagnostics for debugging
        for diag in &undefined_var_diags {
            println!(
                "Diagnostic: {} at line {}",
                diag.message, diag.range.start.line
            );
        }

        // Function parameters a and b should NOT be flagged as undefined
        // Use exact equality to avoid substring false positives (e.g., "a" matching "ab")
        assert!(
            !undefined_var_diags
                .iter()
                .any(|d| d.message == "a is not defined"),
            "Parameter 'a' should not be flagged as undefined"
        );
        assert!(
            !undefined_var_diags
                .iter()
                .any(|d| d.message == "b is not defined"),
            "Parameter 'b' should not be flagged as undefined"
        );
    }

