    #[test]
    fn test_default_parameter_expression_checked() {
        // Test that identifiers in default parameter expressions ARE checked for undefined
        // e.g., function(a = b) should flag 'b' as undefined if not defined
        let mut state = create_test_state();
        let code = r#"
my_func <- function(a = undefined_var) {
  a
}
"#;
        let uri = add_document(&mut state, "file:///test.R", code);
        let tree = parse_r_code(code);
        let root = tree.root_node();

        let mut diagnostics = Vec::new();
        let __snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &__snapshot,
            &uri,
            root,
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        // Filter to only undefined variable warnings
        let undefined_var_diags: Vec<_> = diagnostics
            .iter()
            .filter(|d| {
                crate::diagnostic_code::diagnostic_has_code(
                    &d.code,
                    crate::diagnostic_code::UNDEFINED_VARIABLE,
                )
            })
            .collect();

        // Print diagnostics for debugging
        for diag in &undefined_var_diags {
            println!(
                "Diagnostic: {} at line {}",
                diag.message, diag.range.start.line
            );
        }

        // The parameter name 'a' should NOT be flagged
        assert!(
            !undefined_var_diags
                .iter()
                .any(|d| d.message == "a is not defined"),
            "Parameter name 'a' should not be flagged as undefined"
        );

        // The undefined variable in the default expression SHOULD be flagged
        assert!(
            undefined_var_diags
                .iter()
                .any(|d| d.message == "undefined_var is not defined"),
            "Undefined variable 'undefined_var' in default expression should be flagged"
        );
    }
    #[test]
    fn test_default_parameter_can_reference_later_top_level_helper() {
        let mut state = create_test_state();
        let code = r#"
my_func <- function(x = make_default()) {
  x
}
make_default <- function() 42

other_func <- function(y = still_missing) {
  y
}
"#;
        let uri = add_document(&mut state, "file:///test.R", code);
        let tree = parse_r_code(code);
        let root = tree.root_node();

        let mut diagnostics = Vec::new();
        let __snapshot = DiagnosticsSnapshot::build(&state, &uri).expect("snapshot built");
        collect_undefined_variables_from_snapshot(
            &__snapshot,
            &uri,
            root,
            code,
            DiagnosticSeverity::WARNING,
            &mut diagnostics,
            &mut std::collections::HashMap::new(),
            &DiagCancelToken::never(),
            None,
        );

        let undefined_var_diags: Vec<_> = diagnostics
            .iter()
            .filter(|d| {
                crate::diagnostic_code::diagnostic_has_code(
                    &d.code,
                    crate::diagnostic_code::UNDEFINED_VARIABLE,
                )
            })
            .collect();

        assert!(
            !undefined_var_diags
                .iter()
                .any(|d| d.message.contains("make_default")),
            "Default expression should resolve a top-level helper declared later, \
             because the promise is evaluated after the function is called. \
             Diagnostics: {:?}",
            undefined_var_diags
        );
        assert!(
            undefined_var_diags
                .iter()
                .any(|d| d.message == "still_missing is not defined"),
            "A genuinely missing default expression symbol must still be flagged. \
             Diagnostics: {:?}",
            undefined_var_diags
        );
    }

